static void add_file(args_t *a, char *f) {
    if (a->n_files == a->cap_files) {
        a->cap_files = a->cap_files ? a->cap_files * 2 : 4;
        a->files = (char **)realloc(a->files, a->cap_files * sizeof(char *));
