/* Get pretty name for error messages */
static const char *opt_pretty(const char *name, const char *value_name) {
    static char buf[64];
    if (value_name) {
        snprintf(buf, sizeof(buf), "--%s %s", name, value_name);
    } else {
        snprintf(buf, sizeof(buf), "--%s", name);
